class Solution:
    def garbageCollection(self, garbage, travel):
        prefix = [0]
        for t in travel:
            prefix.append(prefix[-1] + t)
        total = 0
        for t in 'MPG':
            last = -1
            units = 0
            for i, g in enumerate(garbage):
                c = g.count(t)
                units += c
                if c > 0:
                    last = i
            total += units
            if last > 0:
                total += prefix[last]
        return total

