class Solution:
    def garbageCollection(self, garbage, travel):
        prefix = [0] * len(garbage)
        for i in range(1, len(garbage)):
            prefix[i] = prefix[i - 1] + travel[i - 1]
        total = sum(len(g) for g in garbage)
        last = {}
        for i, g in enumerate(garbage):
            for ch in g:
                last[ch] = i
        for ch in last:
            total += prefix[last[ch]]
        return total

